const statsItems = $('Fetch Ad Stats').first().json;
const adsItems = $('Fetch Active Ads').first().json;

const statsData = statsItems.data || statsItems;
const adsData = adsItems.data || adsItems;

if (!Array.isArray(statsData) || !Array.isArray(adsData)) {
  return [{ json: { error: 'Invalid data', actions: [] } }];
}

// Build ads map for current bids
const adsMap = {};
adsData.forEach(ad => {
  adsMap[ad.id] = {
    current_bid: parseFloat(ad.one_bid_for_all_geo) || 0,
    status_id: ad.status_id
  };
});

const maxCeiling = parseFloat($env.MAX_BID_CEILING || '0.10');
const actions = [];

statsData.forEach(d => {
  const adId = d.ad_id;
  const spend = parseFloat(d.money) || 0;
  const revenue = parseFloat(d.postbacks_confirmed_money) || 0;
  const clicks = parseInt(d.clicks_count) || 0;
  const shows = parseInt(d.shows_count) || 0;
  const roi = spend > 0 ? ((revenue - spend) / spend * 100) : 0;
  const ctr = shows > 0 ? (clicks / shows * 100) : 0;
  const currentBid = adsMap[adId]?.current_bid || 0;

  let action = 'HOLD';
  let bidMultiplier = 1.0;
  let reason = '';

  // Rule 1: CTR > 2% AND ROI > 0 = golden teaser
  if (ctr > 2 && roi > 0 && clicks > 10) {
    action = 'RAISE_BID';
    bidMultiplier = 1.20;
    reason = `Golden teaser: CTR ${ctr.toFixed(2)}%, ROI ${roi.toFixed(1)}%`;
  }
  // Rule 2: ROI > 50% with enough data
  else if (roi > 50 && clicks > 20) {
    action = 'RAISE_BID';
    bidMultiplier = 1.10;
    reason = `High ROI ${roi.toFixed(1)}% with ${clicks} clicks`;
  }
  // Rule 3: ROI 0-50% = hold
  else if (roi >= 0 && roi <= 50 && clicks > 20) {
    action = 'HOLD';
    reason = `Stable ROI ${roi.toFixed(1)}%`;
  }
  // Rule 4: ROI -30% to 0% = lower bid
  else if (roi >= -30 && roi < 0 && clicks > 30) {
    action = 'LOWER_BID';
    bidMultiplier = 0.85;
    reason = `Negative ROI ${roi.toFixed(1)}%, lowering 15%`;
  }
  // Rule 5: ROI < -30% = significant lower
  else if (roi < -30 && roi >= -50 && clicks > 20) {
    action = 'LOWER_BID';
    bidMultiplier = 0.70;
    reason = `Bad ROI ${roi.toFixed(1)}%, lowering 30%`;
  }
  // Rule 6: ROI < -50% AND spent > $3 = STOP
  else if (roi < -50 && spend > 3) {
    action = 'STOP';
    reason = `Critical ROI ${roi.toFixed(1)}%, spent $${spend.toFixed(2)} - STOPPING`;
  }
  // Rule 7: Dead teaser (no clicks but many shows)
  else if (clicks < 5 && shows > 1000) {
    action = 'STOP';
    reason = `Dead teaser: ${clicks} clicks / ${shows} shows in 24h`;
  }

  if (action !== 'HOLD') {
    let newBid = currentBid * bidMultiplier;
    if (newBid > maxCeiling) newBid = maxCeiling;
    if (newBid < 0.001) newBid = 0.001;

    actions.push({
      json: {
        ad_id: adId,
        action: action,
        current_bid: currentBid,
        new_bid: action === 'STOP' ? currentBid : Math.round(newBid * 10000) / 10000,
        roi: Math.round(roi * 100) / 100,
        clicks: clicks,
        shows: shows,
        spend: spend,
        ctr: Math.round(ctr * 10000) / 10000,
        reason: reason
      }
    });
  }
});

if (actions.length === 0) {
  return [{ json: { action: 'NONE', reason: 'No bid changes needed' } }];
}

return actions;

